const body = $input.first().json.body || $input.first().json;

const post = body.post || '';
const tech = body.tech || '';
const type = body.type || 'Projet technique';
const unsplashKey = body.unsplashKey || 'YOUR_UNSPLASH_ACCESS_KEY';

const techList = tech.split(',').map(t => t.trim().toLowerCase()).filter(Boolean);
const postLower = post.toLowerCase();

let imageQuery = 'technology developer coding';
let visualType = 'image';
let docLinks = [];
let tips = [];

// Détection intelligente
if (techList.some(t => ['aws', 'ec2', 'lambda', 's3', 'cloudfront', 'dynamodb'].includes(t)) || postLower.includes('aws')) {
  imageQuery = 'AWS cloud infrastructure serverless technology';
  visualType = 'architecture diagram / infra cloud';
  docLinks = [
    { title: 'AWS Architecture Center', url: 'https://aws.amazon.com/architecture/', type: 'reference' },
    { title: 'AWS Pricing Calculator', url: 'https://calculator.aws/', type: 'tool' },
    { title: 'AWS Well-Architected', url: 'https://docs.aws.amazon.com/wellarchitected/latest/framework/welcome.html', type: 'pdf' }
  ];
  tips.push('Ajoutez un diagramme d'architecture Cloudcraft ou Draw.io pour illustrer votre infra AWS');
}

if (techList.some(t => ['react', 'next.js', 'vue', 'angular', 'frontend'].includes(t)) || postLower.includes('react')) {
  imageQuery = techList.some(t => t.includes('aws')) ? 'react developer cloud coding' : 'react javascript frontend developer';
  if (!visualType.includes('diagram')) visualType = 'UI screenshot / component mockup';
  docLinks.push({ title: 'React Documentation', url: 'https://react.dev/', type: 'reference' });
}

if (techList.some(t => ['node.js', 'express', 'fastapi', 'backend'].includes(t))) {
  if (imageQuery === 'technology developer coding') imageQuery = 'nodejs backend server code';
  docLinks.push({ title: 'Node.js Best Practices', url: 'https://github.com/goldbergyoni/nodebestpractices', type: 'github' });
}

if (techList.some(t => ['docker', 'kubernetes', 'k8s', 'devops', 'ci/cd'].includes(t)) || postLower.includes('devops')) {
  imageQuery = 'devops docker kubernetes containers';
  visualType = 'CI/CD pipeline diagram';
  docLinks.push({ title: 'Docker Best Practices', url: 'https://docs.docker.com/develop/dev-best-practices/', type: 'reference' });
}

if (type.toLowerCase().includes('retour') || type.toLowerCase().includes('expérience')) {
  tips.push('Un post "retour d'expérience" performe mieux avec une image "before/after" ou un graphique de metrics');
}

tips.push('Les posts LinkedIn avec image génèrent 40% plus d'engagement');
tips.push('Créditez l'auteur Unsplash si vous utilisez leurs photos');

return [{
  json: {
    imageQuery,
    visualType,
    docLinks,
    tips,
    unsplashKey,
    _meta: { techDetected: techList, postLength: post.length }
  }
}];

const unsplash = $input.first().json;
const analyze = $('Analyze Content').first().json;

let images = [];

if (unsplash.results && unsplash.results.length > 0) {
  images = unsplash.results.map(img => ({
    url: img.urls.regular,
    thumb: img.urls.small,
    alt: img.alt_description || analyze.imageQuery,
    author: img.user.name,
    authorLink: img.user.links.html,
    credit: `Photo by ${img.user.name} on Unsplash`,
    downloadLocation: img.links.download_location
  }));
} else {
  // Fallback si quota Unsplash dépassé ou erreur
  images = [{
    url: 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=800&q=80',
    thumb: 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=400&q=80',
    alt: analyze.imageQuery,
    author: 'NASA',
    authorLink: 'https://unsplash.com/@nasa',
    credit: 'Photo by NASA on Unsplash',
    downloadLocation: ''
  }];
}

return [{
  json: {
    success: true,
    suggestedVisualType: analyze.visualType,
    searchQuery: analyze.imageQuery,
    images,
    documents: analyze.docLinks,
    tips: analyze.tips,
    generatedAt: new Date().toISOString()
  }
}];
